        'service_conditions' => [
            'title'       => '3.- CONDICIONES DEL SERVICIO',
            'text_line_1' => 'Todas las tarifas son por persona y aplican solo para pasajeros extranjeros.',
            'text_line_2' => 'Los precios están sujetos a cambio sin previo aviso y sólo podrán garantizarse una vez efectuada la reserva',
            'text_line_3' => 'Las tarifas no aplican para residentes con permanencia de más de 60 días, ni pasajeros corporativos (de 4 noches a más en Lima).',
