        'anti_bribery_commercial' => [
            'title'       => '13.- ANTISOBORNO, RESTRICCIONES COMERCIALES Y ÉTICA COMERCIAL',
            'text_line_1' => 'LimaTours adopta una política de tolerancia cero respecto a las infracciones de las normas internacionales reguladoras del comercio, incluyendo la legislación en materia de prevención del soborno y la',
            'text_line_2' => 'corrupción y las restricciones aplicables al comercio, el flujo de fondos y la financiación del terrorismo. El CLIENTE garantiza que cumple y seguirá cumpliendo en el futuro, al igual que sus Partes Asociadas',
